'use server';
/**
 * @fileOverview This file defines a Genkit flow for generating personalized indoor cycling workout suggestions.
 *
 * - aiWorkoutSuggester - A function that handles the workout suggestion process.
 * - AIWorkoutSuggesterInput - The input type for the aiWorkoutSuggester function.
 * - AIWorkoutSuggesterOutput - The return type for the aiWorkoutSuggester function.
 */

import {ai} from '@/ai/genkit';
import {z} from 'genkit';

const AIWorkoutGoalSchema = z.enum(['endurance', 'speed', 'recovery', 'VO2 max', 'threshold']);

const AIWorkoutSuggesterInputSchema = z.object({
  ftp: z.number().describe('Functional Threshold Power (FTP) in watts.'),
  goal: AIWorkoutGoalSchema.describe('The fitness goal for the workout (e.g., endurance, speed, recovery, VO2 max, threshold).'),
  durationMinutes: z.number().int().positive().describe('Available training time in minutes.'),
});
export type AIWorkoutSuggesterInput = z.infer<typeof AIWorkoutSuggesterInputSchema>;

const WorkoutBlockSchema = z.object({
  zone: z.enum(['Z1', 'Z2', 'Z3', 'Z4', 'Z5', 'Z6']).describe('The FTP training zone for this block (Z1: Active Recovery, Z2: Endurance, Z3: Tempo, Z4: Threshold, Z5: VO2 Max, Z6: Anaerobic).'),
  durationMinutes: z.number().int().positive().describe('Duration of this workout block in minutes.'),
  description: z.string().describe('A brief description or instruction for this workout block.'),
});

const AIWorkoutSuggesterOutputSchema = z.object({
  workoutName: z.string().describe('A descriptive name for the generated workout.'),
  description: z.string().describe('A general description of the workout and its purpose.'),
  blocks: z.array(WorkoutBlockSchema).describe('An array of workout blocks, each with a zone, duration, and description.'),
});
export type AIWorkoutSuggesterOutput = z.infer<typeof AIWorkoutSuggesterOutputSchema>;

export async function aiWorkoutSuggester(input: AIWorkoutSuggesterInput): Promise<AIWorkoutSuggesterOutput> {
  return aiWorkoutSuggesterFlow(input);
}

const aiWorkoutSuggesterPrompt = ai.definePrompt({
  name: 'aiWorkoutSuggesterPrompt',
  input: {schema: AIWorkoutSuggesterInputSchema},
  output: {schema: AIWorkoutSuggesterOutputSchema},
  prompt: `You are an expert indoor cycling coach and workout designer. Your task is to create a structured indoor cycling workout plan based on the user's Functional Threshold Power (FTP), their fitness goal, and the available training time.

Use the following FTP zone definitions:
- Z1 (Active Recovery): < 55% FTP
- Z2 (Endurance): 56-75% FTP
- Z3 (Tempo): 76-90% FTP
- Z4 (Threshold): 91-105% FTP
- Z5 (VO2 Max): 106-120% FTP
- Z6 (Anaerobic): > 120% FTP

The workout should be composed of several blocks, each assigned to one of these zones (Z1-Z6) with a specific duration and a brief description. Ensure the total duration of all blocks sums up to the user's specified 'durationMinutes'.

Tailor the workout to the specified 'goal'. For example:
- 'endurance': Focus on Z2-Z3 with longer durations.
- 'speed': Include Z5-Z6 intervals with shorter durations and Z1-Z2 recovery.
- 'recovery': Primarily Z1-Z2 with low intensity.
- 'VO2 max': Emphasize Z5 intervals with sufficient recovery.
- 'threshold': Focus on Z4 intervals.

Provide a workout name and an overall description.

User Input:
FTP: {{{ftp}}} watts
Goal: {{{goal}}}
Available Training Time: {{{durationMinutes}}} minutes

Generate the workout plan in JSON format conforming to the output schema.`,
});

const aiWorkoutSuggesterFlow = ai.defineFlow(
  {
    name: 'aiWorkoutSuggesterFlow',
    inputSchema: AIWorkoutSuggesterInputSchema,
    outputSchema: AIWorkoutSuggesterOutputSchema,
  },
  async (input) => {
    const {output} = await aiWorkoutSuggesterPrompt(input);
    if (!output) {
      throw new Error('Failed to generate workout suggestion.');
    }
    return output;
  },
);
